              const x2 = 200 + Math.cos(a) * 200, y2 = 200 + Math.sin(a) * 200;
              return <line key={i} x1={x1} y1={y1} x2={x2} y2={y2} stroke="#e15f41" strokeWidth="1" opacity={i%3===0?0.7:0.3}/>;
            })}
